        // when the app HAS launched (mid-second-bounce), not at the click —
        // the mid-launch flag guards a double-click during the bounce
        const first = !(isCal ? this.calRunning : this.dvRunning) && !(isCal ? this.launching : this.dvLaunching)
        if (first) { if (isCal) this.launching = true; else this.dvLaunching = true }
        const go = () => {
            if (isCal) { this.launching = false; this.calRunning = true; this.calCount = this.calCount + 1 }
            else { this.dvLaunching = false; this.dvRunning = true; this.dvCount = this.dvCount + 1 }
            this.dismissAbouts()
