            ],
        ],

    // the note body is FORMATTED — a Markdown field on the paper (no input
    // chrome, no focus ring; the note's text is authored, not typed)

    pad: View [ x = 12, y = { classroot.barH + 6 }, clip = true,
        width = { parent.width - 24 }, height = { parent.height - classroot.barH - 16 },
        md: Markdown [ width = { parent.width }, dark = false,
            bodyColor = 0x1D1D1F, scale = 0.82, lineHeight = 1.45,
            text = { classroot.note } ],
        ],
    ]


// ── a minimized window's dock tile: an INVISIBLE click target that runs the
// SAME magnification wave as the icons (so its hit area and label track the
// growing thumbnail beneath) — the visual is the WINDOW ITSELF, parked live
// at this slot. The tile sits in the dock layer above the parked window, so
// a click restores instead of poking the tiny content; its pill is the
// DockIcon's, showing the window's title (or its app's name, untitled). ─────

class MiniTile extends View [

    // a STATIC POOL member (no replication, no Dataset): `ix` is assigned at
    // the use site, and every property below is a pure constraint over the
    // app's mini state — one atomic write to miniRecs re-derives the whole
    // tile, so no per-row machinery exists to go stale

    ix: number = 0,
    on: boolean = { app.miniRecs != null && this.ix < app.miniRecs.length },
    visible = { this.on },
    lbl: string = { this.on ? "" + app.miniRecs[this.ix].label : "" },
    kind: string = { this.on ? "" + app.miniRecs[this.ix].kind : "" },
    hovered: boolean = false,

    // geometry straight from THE mini layout (the same entries the parked
    // window reads), translated into the minis section's local space

    slotW: number = { app.miniLayout != null && this.ix < app.miniLayout.length ? app.miniLayout[this.ix].w : 48 },
    slotRestW: number = { app.miniLayout != null && this.ix < app.miniLayout.length ? app.miniLayout[this.ix].rw : 48 },
    waveMag: number = { this.slotW / Math.max(1, this.slotRestW) },
    x = { (app.miniLayout != null && this.ix < app.miniLayout.length ? app.miniLayout[this.ix].x : 0) - (app.dock.x + app.dock.row.width + 17) },
    width = { this.slotW },
    height = { app.iconEdge * this.waveMag },
    y = { parent.height - this.height - 9 },

    onMouseOver() { hovered = true },
    onMouseOut()  { hovered = false },
    onClick() { app.restoreMiniAt(this.ix) },

    // the APP-ICON BADGE — on the TILE (the dock layer, above the plate's
    // frost, so it renders crisp), GATED BY GEOMETRY: it shows exactly while
    // the window is SEATED in this slot — its visual width equals the slot's
    // (both sides derive from the same layout entry, so the equality holds
    // through the magnification wave, and NEVER mid-journey: a traveling or
    // restored window's scale·width can't match). Pure derived fact — no
    // arrival bookkeeping at all.

    seated: boolean = { app.seatCheck(app.miniWins, this.ix, this.slotW, app.winSeq, app.pointerX, app.dock.hot) },

    // the badge is THE APP'S OWN DOCK ICON at badge scale (David's rule) —
    // same class, same art, so the calendar badge carries the live date.
    // Its wave/size/position constraints are displaced at this use site, and
    // its pointer handlers forward to the tile (so no second pill appears).

    badge: DockIcon [
        visible = { classroot.seated },
        width = { app.badgeEdge * classroot.waveMag }, height = { app.badgeEdge * classroot.waveMag },
        x = { parent.width - (app.badgeEdge - 2) * classroot.waveMag },
        y = { parent.height - (app.badgeEdge - 2) * classroot.waveMag },
        kind = { classroot.kind == "calendar" ? "calendar" : classroot.kind == "stickies" ? "stickies" : classroot.kind == "files" ? "files" : "" },
        glyph = { classroot.kind == "markdown" ? "M↓" : classroot.kind == "declareviewer" ? "[  ]" : "" },
        gsize = { classroot.kind == "declareviewer" ? 0.42 : 0.42 },
        hue1 = { classroot.kind == "markdown" ? 0x8E7CE8
            : classroot.kind == "declareviewer" ? 0x2E6FE0
            : classroot.kind == "calendar" ? 0xFFFFFF
            : classroot.kind == "stickies" ? 0xFCF4A7 : 0x59B0F6 },
        hue2 = { classroot.kind == "markdown" ? 0x5A46B8
            : classroot.kind == "declareviewer" ? 0x12A594
            : classroot.kind == "calendar" ? 0xEFEFF2
            : classroot.kind == "stickies" ? 0xF3E27E : 0x1D6FD1 },
        onMouseOver() { classroot.hovered = true },
        onMouseOut()  { classroot.hovered = false },
        onClick() { app.restoreMiniAt(classroot.ix) },
        ],

    // the label pill — the DockIcon's, verbatim geometry: constant screen
    // height, pinned 34px above the dock's top whatever the tile's size

    pill: View [ visible = { hovered },
        width = { this.t.width + 26 }, height = 26, cornerRadius = 9,
        x = { (parent.width - this.width) / 2 },
        y = { parent.height - (this.parent.parent.height - 9 + 34) },
        fill = { app.darkMode ? 0x2E2E33 : 0xF5F5F7 },
        darkRim: Color = #00000059,
        stroke = { stroke(1, app.darkMode && this.darkRim != null ? this.darkRim : 0xD8D8DD) },
        t: Text [ x = center, y = center, fontSize = 13,
            textColor = { app.darkMode ? 0xF2F2F5 : 0x1D1D1F },
            text = { classroot ? "" + classroot.lbl : "" } ],
        tick: View [ width = 10, height = 6, x = { (parent.width - 10) / 2 }, y = 25,
            draw(d) {
                d.fillStyle = app.darkMode ? 0x2E2E33 : 0xF5F5F7
                d.beginPath()
                d.moveTo(0, 0); d.lineTo(10, 0); d.lineTo(5, 5.5)
                d.fill()
                },
            ],
        ],
    ]


// ── a dock icon: drawn, labeled, magnifying BY LAYOUT from resting centers ───

class DockIcon extends View [

    // per-icon inputs, fed at the use site

    ix: number = 0,                              // resting slot index
    slots: number = 9,                           // total icons — keep in step with the dock's row
    name: string = "",                           // the label pill's text
    hue1: Color = #4A90D9,                       // plate gradient, top → bottom
    hue2: Color = #2E5FA3,
    glyph: string = "",                          // a text glyph icon (⌘, ♪, …) …
    gsize: number = 0.42,                        //   … at this fraction of the plate (wide marks set less)
    kind: string = "",                           // … OR drawn art: calendar | notes | mail | terminal | pencil | stickies
    running: boolean = false,
    hovered: boolean = false,

    // shared geometry — one place for the numbers the constraints below share

    rest: number = 48,                           // resting icon size
    pitch: number = 56,                          // slot-center spacing (rest + 8 gap)
    reach: number = 150,                         // magnification falloff radius, px of pointer distance
    strip: number = 9,                           // the running-dot band under the icons

    // the RESTING slot center in app coords — the magnification's source must
    // not read the magnified layout (a feedback loop); resting geometry is
    // fixed: `pitch` about the app's center

    cx0: number = { app.width / 2 + (this.ix - (this.slots - 1) / 2) * this.pitch - app.miniSpan / 2 },

    // inside the strip, magnification TRACKS the pointer with no visible lag —
    // so `near` (the horizontal falloff) is an UNSPRUNG constraint, instant
    // response — and only the enter/exit ENVELOPE (the dock's `hot`, sprung
    // fast, ~100ms) animates. An earlier per-icon spring (~300ms) read as syrup.

    near: number = { Math.max(0, 1 - Math.abs(app.pointerX - this.cx0) / this.reach) },
    env: number = { this.parent.parent.hot },

    // the REAL width grows to 1.5× at the peak: neighbors displace, the
    // plate's edges push outward — magnification by layout, not paint

    width  = { this.rest * (1 + 0.5 * Math.pow(Math.max(0, this.near * this.env), 2)) },
    height = { this.width },
    y = { parent.height - this.height - this.strip - this.hopY },   // bottom-anchored above the dot strip

    // the LAUNCH BOUNCE (Apple's): a ballistic arc — decelerating up, gravity
    // down — twice, ~560ms per bounce, poked by the app on an application's
    // FIRST open (or its first after a Quit). The group cascades `attribute`
    // to its members; each leg is one half of the parabola.

    hopY: number = 0,

    bounce: AnimatorGroup [ attribute = hopY, process = sequential,
        Animator [ to = 30, duration = 300, motion = quadOut ],
        Animator [ to = 0, duration = 260, motion = quadIn ],
        Animator [ to = 30, duration = 300, motion = quadOut ],
        Animator [ to = 0, duration = 260, motion = quadIn ],
        ],

    poke() { this.bounce.start() },

    onMouseOver() { hovered = true },
    onMouseOut()  { hovered = false },

    plate: View [ x = 0, y = 0, width = { parent.width }, height = { parent.height },
        cornerRadius = { parent.width * 0.23 }, clip = true,
        fill = { gradient(this.parent.hue1, this.parent.hue2) },

        // glyph sizes stay FRACTIONAL: rounding them made the art tick in
        // whole-pixel steps while the plate glides subpixel — visible jitter

        g: Text [ x = center, y = center, fontWeight = semibold, textColor = 0xFFFFFF,
            fontSize = { this.parent.width * classroot.gsize },
            visible = { classroot.glyph != "" },
            text = { classroot ? "" + this.parent.parent.glyph : "" } ],

        // drawn app art, authored in the RESTING 48-box and scaled with the
        // plate — the plausible-Mac-app set the dock's wave needed

        art: View [ x = 0, y = 0, width = 48, height = 48,
            visible = { classroot.kind != "" },
            scale = { this.parent.width / classroot.rest },
            draw(d) {
                const k = classroot.kind
                // rounded rectangle on the path (the draw surface has arcs,
                // not a roundRect) — shared by the folder's panels
                const rr = (x, y, w, h, r) => {
                    d.moveTo(x + r, y)
                    d.lineTo(x + w - r, y); d.arc(x + w - r, y + r, r, -Math.PI / 2, 0, false)
                    d.lineTo(x + w, y + h - r); d.arc(x + w - r, y + h - r, r, 0, Math.PI / 2, false)
                    d.lineTo(x + r, y + h); d.arc(x + r, y + h - r, r, Math.PI / 2, Math.PI, false)
                    d.lineTo(x, y + r); d.arc(x + r, y + r, r, Math.PI, Math.PI * 1.5, false)
                    d.closePath()
                    }
                if (k == "calendar") {
                    d.fillStyle = 0xFFFFFF
                    d.fillRect(0, 0, 48, 48)
                    d.fillStyle = 0xFB4238
                    d.fillRect(0, 0, 48, 13)
                    }
                else if (k == "files") {
                    // the folder: a back panel with its tab, then a brighter
                    // front panel over the lower half — two whites on the
                    // plate's blue
                    d.fillStyle = 0xD9E7FA
                    d.beginPath()
                    rr(9, 13.5, 14, 8, 2)
                    d.fill()
                    d.beginPath()
                    rr(9, 16, 30, 19, 2.5)
                    d.fill()
                    d.fillStyle = 0xFFFFFF
                    d.beginPath()
                    rr(9, 20, 30, 15, 2.5)
                    d.fill()
                    }
                else if (k == "mail") {
                    d.fillStyle = 0xFFFFFF
                    d.beginPath()
                    d.moveTo(9, 15); d.lineTo(39, 15); d.lineTo(39, 34); d.lineTo(9, 34)
                    d.closePath(); d.fill()
                    d.strokeStyle = 0xB9C6DB
                    d.lineWidth = 1.6
                    d.beginPath()
                    d.moveTo(9.5, 15.8); d.lineTo(24, 26); d.lineTo(38.5, 15.8)
                    d.stroke()
                    }
                else if (k == "terminal") {
                    d.strokeStyle = 0xFFFFFF
                    d.lineWidth = 2.6
                    d.lineCap = "round"
                    d.beginPath()
                    d.moveTo(14, 18.5); d.lineTo(20, 24); d.lineTo(14, 29.5)
                    d.moveTo(24, 30); d.lineTo(32.5, 30)
                    d.stroke()
                    }
                else if (k == "pencil") {
                    // the pencil, drawn: eraser upper-left, TIP LOWER-RIGHT
                    // (a horizontal flip of the glyph it replaces), spanning
                    // most of the plate. Body + tip in white; the eraser seam
                    // and ferrule struck back across it in the plate's hue.
                    d.fillStyle = 0xFFFFFF
                    d.beginPath()
                    d.moveTo(7.8, 12.2); d.lineTo(14.2, 5.8); d.lineTo(35.7, 27.3); d.lineTo(29.3, 33.7)
                    d.closePath(); d.fill()
                    d.beginPath()
                    d.moveTo(35.7, 27.3); d.lineTo(29.3, 33.7); d.lineTo(39.5, 37.5)
                    d.closePath(); d.fill()
                    d.strokeStyle = classroot.hue1
                    d.lineWidth = 1.6
                    d.beginPath()
                    d.moveTo(11.4, 15.7); d.lineTo(17.7, 9.4)
                    d.moveTo(13.5, 17.8); d.lineTo(19.8, 11.5)
                    d.stroke()
                    }
                else if (k == "stickies") {
                    // the sticky note: all-yellow paper, saturated strip,
                    // faint ruled lines, a folded corner — kin to the real
                    // Stickies icon, distinct from the white Notes plate
                    d.fillStyle = 0xF3DC49
                    d.fillRect(0, 0, 48, 10)
                    d.strokeStyle = 0xE0CE66
                    d.lineWidth = 2
                    d.beginPath()
                    d.moveTo(8, 19); d.lineTo(40, 19)
                    d.moveTo(8, 27); d.lineTo(40, 27)
                    d.moveTo(8, 35); d.lineTo(26, 35)
                    d.stroke()
                    d.fillStyle = 0xE9D76A
                    d.beginPath()
                    d.moveTo(48, 33); d.lineTo(33, 48); d.lineTo(48, 48)
                    d.closePath(); d.fill()
                    }
                },
            ],

        // the calendar's LIVE face — the real weekday and day, from the clock

        // the weekday sits CENTERED in the red band (13/48 of the plate)

        cwk: Text [ x = center, y = { (this.parent.width / 48 * 13 - this.height) / 2 },
            fontWeight = bold, textColor = 0xFFFFFF,
            fontSize = { Math.max(6, this.parent.width * 0.16) },
            visible = { classroot.kind == "calendar" },
            text = { app.dayName } ],
        cnum: Text [ x = center, y = { this.parent.height * 0.26 }, textColor = 0x1D1D1F,
            fontSize = { this.parent.width * 0.56 },
            visible = { classroot.kind == "calendar" },
            text = { "" + app.dayNum } ],
        ],

    // the running-app dot, centered in the strip below the icon

    // the dot marks IS-RUNNING and never bounces: adding hopY back cancels the
    // icon's launch-bounce offset, pinning the dot to the strip

    dot: View [ width = 4, height = 4, cornerRadius = 2,
        x = { (parent.width - 4) / 2 }, y = { parent.height + 3 + this.parent.hopY },
        visible = { running }, fill = { theme.textMuted } ],

    // the label pill — the dock's own quasi-tooltip: a frosted chip with a
    // pointer tick, NO shadow, and a CONSTANT screen height. The icon under it magnifies; the pill must not ride it —
    // its y is written so the icon's own bottom-anchored y CANCELS out,
    // pinning the pill 34px above the dock's top whatever the icon's size.

    pill: View [ visible = { hovered },
        width = { this.t.width + 26 }, height = 26, cornerRadius = 9,
        x = { (parent.width - this.width) / 2 },
        y = { parent.height - (this.parent.parent.height - classroot.strip + 34) },
        fill = { app.darkMode ? 0x2E2E33 : 0xF5F5F7 },
        darkRim: Color = #00000059,
        stroke = { stroke(1, app.darkMode && this.darkRim != null ? this.darkRim : 0xD8D8DD) },
        t: Text [ x = center, y = center, fontSize = 13,
            textColor = { app.darkMode ? 0xF2F2F5 : 0x1D1D1F },
            text = { classroot ? "" + this.parent.parent.name : "" } ],
        tick: View [ width = 10, height = 6, x = { (parent.width - 10) / 2 }, y = 25,
            draw(d) {
                d.fillStyle = app.darkMode ? 0x2E2E33 : 0xF5F5F7
                d.beginPath()
                d.moveTo(0, 0); d.lineTo(10, 0); d.lineTo(5, 5.5)
                d.fill()
                },
            ],
        ],
    ]


// The desktop TRACKS the browser window: no size floor (a floor makes the
// page scroll — a desktop never scrolls), and the root CLIPS, so windows
// hanging past an edge are cropped where they lie, never moved. Everything
// anchored to edges (menu bar width, the clock's right edge, the dock's
// bottom seat) re-derives from app.width/app.height on every host resize.

App [ clip = true,
    theme = { Themes.cupertino(app.darkMode) },
    fontFamily = "-apple-system, system-ui, sans-serif",

    // the wallpaper — a plain gradient, darkened with the appearance

    fill = { app.darkMode ? gradient(0x2A3A55, 0x18222F) : gradient(0x7FA8D9, 0x4A6FA5) },

    // ── shared desktop geometry: named once, read by every constraint below ──

    menuBarH: number = 32,                       // the system menu bar's height; windows live below it
    iconEdge: number = 48,                       // a dock icon's resting edge — the cell every dock citizen shares
    dockFloor: number = 13,                      // the icons' resting bottom line, up from the desktop's bottom edge
    badgeEdge: number = 18,                      // a minimized window's app badge, at rest (hangs 2px past the thumb)

    // activation is ONE View-typed slot: every window derives its look (shadow
    // depth, bar tone, lights) from whether it IS this value

    frontWin: View = null,
    winCount: number = 0,                        // ever-opened count — staggers spawn positions
    viewerCount: number = 0,                     // open viewers, for the dock's running dot

    // ── the application model: three "applications" share this desktop —
    // Files (the Finder), Markdown (the viewer), and Declare Calendar (the
    // hosted app) — and the menu bar is CONTEXTUAL: it belongs to the front
    // window's application, exactly as the Mac's does. A window's app is
    // read from its class; About windows carry theirs explicitly.

    pathOf(w) { return w != null && w.appPath ? "" + w.appPath : "" },   // any-seam: an AppWindow's program

    appOf(w) {
        if (w == null) return "files"
        const c = w.constructor.name
        if (c == "ViewerWindow") return "markdown"
        if (c == "StickyWindow") return "stickies"
        if (c == "AppWindow") return this.pathOf(w).indexOf("viewer") >= 0 ? "declareviewer" : "calendar"
        if (c == "AboutWindow") return "" + w.forApp
        return "files"
        },

    activeApp: string = { this.appOf(app.frontWin) },

    nameOf(a) {
        return a == "markdown" ? "Markdown" : a == "calendar" ? "Declare Calendar"
            : a == "declareviewer" ? "Declare Viewer"
            : a == "stickies" ? "Stickies"
            : a == "desktop" ? "Declare Desktop" : "Files"
        },

    // View & Edit Source opens the RUNNING PROGRAM ITSELF in the Declare
    // Viewer — as an EMBEDDED APP in a desktop window: the AppWindow hosts
    // apps/viewer, and `program=` in its env segment names the subject (a
    // path valid in THIS app's transport base). The viewer self-loads that
    // program's ?segments and ?file artifacts — reader mode by default.

    sourceRel(a) {
        return a == "calendar" ? "../calendar/calendar.declare"
            : a == "declareviewer" ? "../viewer/viewer.declare"
            : "desktop.declare"
        },

    openSource(a) {
        this.openApp("../../viewer/viewer", "Declare Viewer", null, "program=" + this.sourceRel(a))
        },

    // ── the command seam: the menu bar, the dock, and keys all route here ──

    command(id) {
        if (id == "new") {
            if (activeApp == "markdown") this.openViewer("../../docs/declare.md", "declare.md")
            else if (activeApp == "calendar") this.openApp("../../calendar/calendar", "Calendar", null, "base=../calendar/")
            else if (activeApp == "declareviewer") this.openApp("../../viewer/viewer", "Declare Viewer", null, "program=desktop.declare")
            else if (activeApp == "stickies") this.newSticky("", null)
            else this.newFinder()
            }
        else if (id == "open") {
            if (activeApp == "declareviewer") this.openApp("../../viewer/viewer", "Declare Viewer", null, "program=desktop.declare")
            else if (activeApp == "stickies") this.newSticky("", null)
            else this.openViewer("../../docs/declare.md", "declare.md")
            }
        else if (id == "close") { if (frontWin != null) this.closeWin(frontWin) }
        else if (id == "dark") app.darkMode = !app.darkMode
        else if (id == "about-desktop") this.openAbout("desktop")
        else if (id == "about-app") this.openAbout(this.activeApp)
        else if (id == "source-desktop") this.openSource("desktop")
        else if (id == "source") this.openSource(this.activeApp)
        else if (id == "quit") this.quitApp(this.activeApp)
        else if (id.indexOf("win:") == 0) this.focusWin(this.wins.children[+id.slice(4)])
        },

    focusWin(w) { if (w == null) return; if (this.isMin(w)) this.restoreMini(w); else w.activate() },

    // Quit closes every window of that application — each by its own reverse
    // zoom — and clears its RUNNING flag (Files has no Quit: like the Finder,
    // it's always running). Running is an APPLICATION state, not a window
    // count: closing the last window leaves the app running (and its dock
    // dot lit), exactly as macOS does — only Quit ends it.

    quitApp(a) {
        const doomed = this.wins.children.filter((w) => this.appOf(w) == a)
        for (const w of doomed) this.closeWin(w)
        if (a == "markdown") mdRunning = false
        else if (a == "calendar") calRunning = false
        else if (a == "declareviewer") dvRunning = false
        else if (a == "stickies") stRunning = false
        },

    // a dock icon's click, macOS's way: a running app's icon RAISES its open
    // windows (in their stacking order, so the front one ends front); with
