        const go = () => {
            mdLaunching = false
            mdRunning = true
            viewerCount = viewerCount + 1
            this.dismissAbouts()
            winCount = winCount + 1
            winSeq = winSeq + 1
            const wx = 160 + (winCount % 7) * 28
            const wy = 36 + (winCount % 7) * 26
